// Recupera o ranking atual do contexto global (persiste enquanto Node-RED estiver rodando)
var ranking = global.get('ranking') || [];

var tag   = msg.payload.tag;
var score = msg.payload.score;

// Verifica se a tag já existe no ranking
var idx = ranking.findIndex(function(r) { return r.tag === tag; });

if (idx >= 0) {
    // Atualiza só se a nova pontuação for maior
    if (score > ranking[idx].score) {
        ranking[idx].score = score;
    }
} else {
    // Nova tag: adiciona ao ranking
    ranking.push({ tag: tag, score: score });
}

// Ordena do maior para o menor score
ranking.sort(function(a, b) { return b.score - a.score; });

// Mantém apenas o Top 10
ranking = ranking.slice(0, 10);

// Salva de volta no contexto global
global.set('ranking', ranking);

// Formata para o ui_table (precisa de array de objetos com posição)
var tabela = ranking.map(function(r, i) {
    return {
        '#':     i + 1,
        'TAG':   r.tag,
        'Score': r.score
    };
});

msg.payload = tabela;
return msg;

// Só inicializa se ainda não existir — preserva dados entre deploys
if (!global.get('ranking')) {
    global.set('ranking', []);
    node.log('Ranking inicializado.');
}
return null;
